<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{ $t('Update') }}</h4>
                    <span class="user-guide">
                        <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG" role="button" aria-expanded="false" aria-controls="collapseExample"> <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                        <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                            <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                <div class="con" v-html="$t('RateScheduleBulckUpdate')"></div>
                            </div>
                        </div>
                    </span>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <dynamic-form lang="en" ref="ResourceRate" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from "../../../services/DataService";
export default {
    props: {
        EditData: {
            type: Array,
            required: false,
        },
    },
    data() {
        return {
            isLoading: false,
            isBillingType: false,
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            companyId: null,
            userId: null,
            PageSize: 100,
            PageNumber: 1,
            searchCondition: '',
            GroupNewData: [],
            UtiltityNames: [],
            StateNames: [],
            WorkCodes: [],
            StatusData: [],
            originalRate: null,
            originalEndDate: null,
            FormSchema: [{
                layoutType: "four",
                Data: [
                    {
                        astype: "toggleField",
                        label: this.$t('Want to Update Rate'),
                        name: "updateRateToggle",
                        value: false,
                        placeholder: "",
                        config: {
                            onChange: this.RateRadion
                        },
                        visibility: true
                    },
                    {
                        astype: "NumericField",
                        label: this.$t('Rate'),
                        name: "Rate",
                        value: "",
                        placeholder: this.$t('Enter New Rate'),
                        // validationRules: {
                        //     "required": true
                        // },
                        config: {
                            options: [],
                        },
                        visibility: true,
                        disabled: true,
                    },
                    {
                        astype: "toggleField",
                        label: this.$t('Want to Update End Date'),
                        name: "updateEndDateToggle",
                        value: false,
                        placeholder: "",
                        config: {
                            onChange: this.RadionEnddate
                        },
                        visibility: true
                    },
                    {
                        astype: "DateField",
                        label: this.$t('End Date (M/D/YYYY)'),
                        name: "EndDate",
                        value: '',
                        visibility: true,
                        placeholder: this.$t('Select New End Date'),
                        // validationRules: {
                        //     "required": true
                        // },
                        config: {
                            format: "MM/DD/YYYY"
                        },
                        visibility: true,
                        disabled: true,
                    },
                ]
            }],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Update",
                    isVisible: true,
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        this.isBillingType = localStorage.getItem("billingType") === "USIC";
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        
        if (vm.EditData && vm.EditData.length > 0) {
            vm.originalRate = vm.EditData[0].RATE || vm.EditData[0].rate || null;
            
            vm.originalEndDate = vm.EditData[0].END_DATE || vm.EditData[0].endDate || null;
            
            console.log("Original Rate:", vm.originalRate);
            console.log("Original End Date:", vm.originalEndDate);
        }
        
        (vm.FormSchema)[0].Data[1].disabled = true;
        (vm.FormSchema)[0].Data[3].disabled = true;
        
        (vm.FormSchema)[0].Data[0].value = false;
        (vm.FormSchema)[0].Data[2].value = false;
        
        (vm.FormSchema)[0].Data[1].value = vm.originalRate || '';
        (vm.FormSchema)[0].Data[3].value = vm.formatDateForForm(vm.originalEndDate) || '';
    },
    methods: {
        RateRadion(data) {
            const vm = this;
            (vm.FormSchema)[0].Data[1].disabled = !data;
            
            if (data) {
                (vm.FormSchema)[0].Data[1].value = vm.originalRate || '';
            } else {
                (vm.FormSchema)[0].Data[1].value = vm.originalRate || '';
            }
        },

        RadionEnddate(data) {
            const vm = this;
            (vm.FormSchema)[0].Data[3].disabled = !data;
            
            if (data) {
                (vm.FormSchema)[0].Data[3].value = vm.formatDateForForm(vm.originalEndDate) || '';
            } else {
                (vm.FormSchema)[0].Data[3].value = vm.formatDateForForm(vm.originalEndDate) || '';
            }
            
            if (data && vm.EditData.length > 0) {
                console.log("Current end date in data:", vm.EditData[0].END_DATE);
            }
        },
        
        formatDateForForm(dateString) {
            if (!dateString) return '';
            
            try {
                const date = new Date(dateString);
                if (isNaN(date.getTime())) return '';
                
                const month = (date.getMonth() + 1).toString().padStart(2, '0');
                const day = date.getDate().toString().padStart(2, '0');
                const year = date.getFullYear();
                
                return `${month}/${day}/${year}`;
            } catch (error) {
                console.error("Date formatting error:", error);
                return '';
            }
        },

        onSubmit(formfields, val) {
            debugger;
            var vm = this;
            
            const rateField = this.FormSchema[0].Data.find(f => f.name === "Rate");
            const endDateField = this.FormSchema[0].Data.find(f => f.name === "EndDate");
            
            const rateToggle = this.FormSchema[0].Data.find(f => f.name === "updateRateToggle");
            const endDateToggle = this.FormSchema[0].Data.find(f => f.name === "updateEndDateToggle");

            const isRateUpdateEnabled = rateToggle.value;
            const isEndDateUpdateEnabled = endDateToggle.value;
            
            
            
            if (!isRateUpdateEnabled && !isEndDateUpdateEnabled) {
                vm.ShowAlert(vm.$t("Please enable at least one field to update"), "warning", true, vm.$t("Alert"));
                return;
            }
            
            const hasRateValue = isRateUpdateEnabled && formfields.Rate && formfields.Rate.toString().trim() !== '';
            const hasEndDateValue = isEndDateUpdateEnabled && formfields.EndDate && formfields.EndDate.toString().trim() !== '';
            
            if ((isRateUpdateEnabled && !hasRateValue) || (isEndDateUpdateEnabled && !hasEndDateValue)) {
                vm.ShowAlert(vm.$t("Please fill in all enabled fields"), "warning", true, vm.$t("Alert"));
                return;
            }

            debugger;
            
            if (isEndDateUpdateEnabled && hasEndDateValue && vm.EditData.length > 0) {
                const startDateStr = vm.EditData[0].START_DATE || vm.EditData[0].startDate;
                const endDateStr = formfields.EndDate;
                
                if (startDateStr) {
                    const startDate = new Date(startDateStr);
                    const endDate = new Date(endDateStr);
                    
                    startDate.setHours(0, 0, 0, 0);
                    endDate.setHours(0, 0, 0, 0);
                    
                    if (endDate <= startDate) {
                        vm.ShowAlert("Start Date should be less than End Date", "warning", true, vm.$t("Alert"));
                        return;
                    }
                }
            }
            
            let rateValue = '';
            let endDateValue = '';
            
           
            if (isRateUpdateEnabled && hasRateValue) {
                rateValue = formfields.Rate.toString();
            } 
            
            
            if (isEndDateUpdateEnabled && hasEndDateValue) {
                if (formfields.EndDate instanceof Date) {
                    endDateValue = formfields.EndDate.toISOString().split('T')[0];
                } else {
                    endDateValue = formfields.EndDate;
                }
            }
            
            var objData = {
                RateScheduleId: vm.EditData.map(x => x.RATE_SCHEDULE_ID).join(","),
                ClientId: vm.EditData.length > 0 ? vm.EditData[0].CLIENT_ID : null,
                Rate: rateValue,                    
                EndDate: endDateValue,
                UpdateRate: isRateUpdateEnabled,
                UpdateEndDate: isEndDateUpdateEnabled
            };
          
            DataService.BulkUpdateRate(JSON.stringify(objData)).then(response => {
                if (response.data != null) {
                    const Result = JSON.parse(response.data)[0];
                    debugger;
                    if (parseInt(Result.RESULT) === 1) {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('RateSchedule')]), "success", true, vm.$t("Alert"));
                        vm.Close();
                    } else {
                        vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
                    }
                }
            }).catch(error => {
                console.error("API Error:", error);
                vm.ShowAlert(vm.$t("UpdateFailed"), "failure", true, vm.$t('Alert'));
            });
        },
        
        Close: function () {
            if (this.isBillingType) {
                this.$parent.FetchData();
                this.$parent.isBulkUpdateRate = false;
            } else {
                this.$parent.isBulkUpdateRate = false;
            }
        }
    }
}
</script>