    methods: {

UpdateCopyRateSchedule() {
    debugger;
    
    if (!this.selectedRateIds || this.selectedRateIds.length === 0) {
        this.ShowAlert(
            this.$t("PleaseSelectAnyRecordsForFurther"),
            "warning",
            true,
            this.$t("Alert")
        );
        return;
    }
    
    const selectedRows = this.RateScheduledeListing.filter(x =>
        this.selectedRateIds.includes(x.RATE_SCHEDULE_ID)
    );
    
    const jsonPayload = selectedRows.map(row => ({
        RateScheduleId: row.RATE_SCHEDULE_ID,
        ClientId: row.CLIENT_ID,
        WorkCodeId: row.WORKCODE_ID,
        UtilityId: row.UTILITY_ID,
        State: row.STATE_CODE,
        StartDate: row.New_Start_Date,
        EndDate: row.New_End_Date,
        Rate: row.New_Rate,
        Comment: row.COMMENT || "",  
        Notes: row.NOTES || "",
        StatusId: row.STATUS_ID,
        optionselected: row.action,
        OriginalStartDate: row.START_DATE,
        OriginalEndDate: row.END_DATE,
        OriginalRate: row.AMOUNT || row.RATE
    }));
    
    const params = {
        jsonString: JSON.stringify(jsonPayload),
        optionselected: jsonPayload[0].optionselected
    };
    
    this.isLoading = true;
    
    DataService.UpdateRates(params)
        .then(res => {
            this.isLoading = false;
            
            if (res && res.data) {
                if (res.data.result === '1') {
                    this.ShowAlert(
                        this.$t("RecordUpdatedSuccessfully"),
                        "success",
                        true,
                        this.$t("Alert")
                    );
                    
                    this.RateScheduledeListing = this.RateScheduledeListing.filter(
                        row => !this.selectedRateIds.includes(row.RATE_SCHEDULE_ID)
                    );
                    
                    this.selectedRateIds = [];
                    this.isShownCopyButton = false;
                    
                    this.Headers.forEach(col => {
                        if (
                            col.COLUMN_NAME === "New_Start_Date" ||
                            col.COLUMN_NAME === "New_End_Date" ||
                            col.COLUMN_NAME === "New_Rate" ||
                            col.COLUMN_NAME === "comment"
                        ) {
                            col.VISIBLE = false;
                        }
                    });
                    
                    this.FetchData();
                } 
                else if (res.data.result === '-3') {
                    this.ShowAlert(
                        "Rate for utilites already exists please change the date range for following utilities :-",
                        "warning",
                        true,
                        "Date Overlap"
                    );
                }
                else if (res.data.result === '-2') {
                    this.ShowAlert(
                        res.data.msg || "Rate for utilities already exists. Please change date range.",
                        "warning",
                        true,
                        "Utility Overlap"
                    );
                }
                else {
                    this.ShowAlert(
                        res.data.msg || this.$t("UnknownError"),
                        "failure",
                        true,
                        this.$t("Alert")
                    );
                }
            } else {
                this.ShowAlert(
                    this.$t("UnknownError"),
                    "failure",
                    true,
                    this.$t("Alert")
                );
            }
        })
        .catch(error => {
            this.isLoading = false;
            console.error(error);
            
            this.ShowAlert(
                this.$t("UnknownError"),
                "failure",
                true,
                this.$t("Alert")
            );
        });
},
handleSaveComment(updatedData) {
    debugger;
    const index = this.RateScheduledeListing.findIndex(
        item => item.RATE_SCHEDULE_ID === updatedData.RATE_SCHEDULE_ID
    );
    
    if (index !== -1) {
        this.$set(this.RateScheduledeListing, index, {
            ...this.RateScheduledeListing[index],
            COMMENT: updatedData.COMMENT || ""
        });
    }
    
    this.closeCommentModal();
},
closeCommentModal() {
    debugger;
    this.isSetCommnet = false;
},

openSelectedRecords(payload) {
    debugger;

    this.isCopyRate = false;
    this.selectedRateIds = payload.ids.map(Number);
    this.isShownCopyButton = true;

    this.Headers.forEach(col => {
        if (
            col.COLUMN_NAME === "New_Start_Date" ||
            col.COLUMN_NAME === "New_End_Date" ||
           col.COLUMN_NAME === "New_Rate" ||
           col.COLUMN_NAME === "comment"
        ) {
            col.VISIBLE = true;
        }
    });

    this.RateScheduledeListing.forEach(row => {
        if (this.selectedRateIds.includes(row.RATE_SCHEDULE_ID)) {

            row.New_Start_Date = payload.newStartDate
                ? this.$options.filters.formatDate(payload.newStartDate)
                : '--';

            row.New_End_Date = payload.newEndDate
                ? this.$options.filters.formatDate(payload.newEndDate)
                : '--';
                row.New_Rate = row.AMOUNT;
                row.action = payload.action || null;
        }
    });

    this.refreshKey++;

    this.$nextTick(() => {
        setTimeout(() => {
            $('.left-search, .tg-left-search, .search-panel').hide();
            $('table tbody tr').hide();
            this.leftSearchFields=[]; 
            this.TotalRecords=[];

            $('.chkItems:checkbox').each(function () {
                const id = Number($(this).val());
                if (payload.ids.includes(id)) {
                    const row = $(this).closest('tr');
                    row.show();
                    row[0].scrollIntoView({
                        behavior: 'smooth',
                        block: 'center'
                    });
                }
            });
        }, 150);
    });
},




       leftCommonSearch: function (value) {
    //debugger
    var vm = this;

    vm.PageNumber = value.PageNumber;
    vm.isPaged = 1;

    vm.searchByState = '';
    vm.searchByUtility = '';
    vm.workCodes = '';

    let searchCondition = '';
    if (typeof value.searchCondition !== 'undefined') {
        searchCondition = value.searchConditionJson && value.searchConditionJson !== ''
            ? value.searchConditionJson
            : value.searchCondition || "";
    }

    /* ================= MAP SEARCH VALUES ================= */
    if (searchCondition) {

        let params = new URLSearchParams(searchCondition);

        if (params.has('State')) {
            vm.searchByState = params.get('State');
        }

        if (params.has('UtilityName')) {
            vm.searchByUtility = params.get('UtilityName');
        }

        if (params.has('Workcode')) {
            vm.workCodes = params.get('Workcode');
        }

        vm.FetchData();
    } 
    else {
        vm.RateScheduledeListing = [];
        vm.TotalRecords = 0;
        vm.PageNumber = 1;
        vm.refreshKey += 1;
    }
},


       commonHeaderButtonClick(event) {
         switch (event.callbackfunction) {
            case "Inactive":
                    this.UpdataStatus(1002);
                    break;
                     case "AddRateSchedule":
                    this.AddRateSchedule();
                    break;
                    case "Update":
                    this.BulkUpdateRate();
                    break;
                    case "CopyRate":
                    this.CopyRate();
                    break;
                     case "ViewHistory":
                    this.ViewHistory();
                    break;
                     case "Remove":
                    this.DeleteData();
                    break;
            }
            
            
        },
DeleteData: function () {
    debugger
    var vm = this;
    var val = "";

    $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
        if (val.length > 0)
            val += ',';
        val += $(this).val();
    });

    if (val.length > 0) {
        vm.confirmR(
            vm.$t("ConfirmDelete"),
            true,
            vm.$t("Delete") + " " + vm.$t("RateSchedule"),
            function () {

                let url = `ids=${val}&tableName=TALYGEN_BE_rate_schedule&primaryKey=RATE_SCHEDULE_ID`;

                DataService.Delete(url).then(response => {

                    if (response.data === "DeletedSuccess") {

                        let ids = val.split(',').map(Number);
                        vm.RateScheduledeListing = vm.RateScheduledeListing.filter(
                            x => !ids.includes(x.RATE_SCHEDULE_ID)
                        );

                        vm.ShowAlert(
                            vm.$t('DeletedSuccessfully'),
                            "success",
                            true,
                            vm.$t('Alert')
                        );

                    } else {
                        vm.ShowAlert(
                            vm.$t('DeletedError'),
                            "failure",
                            true,
                            vm.$t('Alert')
                        );
                    }

                 
                });
            }
        );
    } else {
        vm.ShowAlert(
            vm.$t("Selectanyrecordtodelete"),
            "failure",
            true,
            vm.$t("Alert")
        );
    }
},

  CopyRate() {
    debugger
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                if (val.length > 0) {
                    val += ',';
                }
                val += $(this).val();
            });
            let ids = val.split(',').map(Number);
             if (val.length > 0) {
                     var vm = this;
                    vm.EditData =vm.RateScheduledeListing.filter(x => ids.includes(x.RATE_SCHEDULE_ID))
                    vm.isCopyRate = true;
                }
            else {
                vm.ShowAlert(vm.$t("PleaseSelectAnyRecordsForFurther"), "warning", true, vm.$t("Alert"));
            }  
           
        },
               BulkUpdateRate () {
                debugger
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                if (val.length > 0) {
                    val += ',';
                }
                val += $(this).val();
            });
            let ids = val.split(',').map(Number);
             if (val.length > 0) {
                 vm.EditData = vm.RateScheduledeListing.filter(x => ids.includes(x.RATE_SCHEDULE_ID));
                 vm.isBulkUpdateRate = true;
            }
            else {
                vm.ShowAlert(vm.$t("PleaseSelectAnyRecordsForFurther"), "warning", true, vm.$t("Alert"));
            }           
        },
      UpdataStatus(StatusID, ID) {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                if (val.length > 0) {
                    val += ',';
                }
                val += $(this).val();
            });

            vm.confirmR(vm.$t('ChanggingActivetoInactive'), true, false, function (result) {
                var postJSON = {
                    ID: val || ID,
                    StatusId: StatusID,
                    IsFor: "TALYGEN_BE_RATE_SCHEDULE",
                    Module: "RateSchedule",
                    Submodule: "Rate Schedule",
                };
                var objectPostString = JSON.stringify(postJSON);
                DataService.CommonUpdateStatus(objectPostString).then(async response => {
                    if (response.status == 200) {
                        $('.chkItems:checkbox:checked').prop("checked", false).removeAttr('checked');
                        vm.listheaderbuttons[0].isdisabled = true;                       
                        vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                        vm.FetchData();

                    }
                });
            })
        },



        async CheckExtraFeatures() {
            //debugger
            var vm = this;
            const params = `featureCode=GET_EXTRA_FEATURE_BILLING&outputType=list`;
            try {
                const response = await DataService.CheckExtraFeatures(params);
                if (response.data) {
                    const features = JSON.parse(response.data);
                    features.forEach(feature => {
                        if (feature.FEATURE_CODE === 'SUBSCRIPTION_BILLING') {
                            vm.IsSubscriptionBilling = true;
                        }
                        if (feature.FEATURE_CODE === 'UTILITY_BILLING') {
                            vm.IsUtilityBilling = true;
                        }
                    });
                }
            } catch (error) {

                console.log("Error checking extra features:", error);
            }
        },

        async FetchData() {
            debugger
            var vueObj = this;
            vueObj.RateScheduledeListing = [];
             const userDate = vueObj.getUserDate();
            var url = `clientId=${vueObj.clientId}&pageSize=${vueObj.pageSize}&pageNum=${vueObj.pageNum}&sortBy=${vueObj.sortBy}&sortExp=${vueObj.sortExp}&isBillingType=${vueObj.isBillingType}&clientIds=${vueObj.clientIds ?? ''}&workCodes=${vueObj.workCodes ?? ''}&searchByState=${vueObj.searchByState ?? ''}&searchByUtility=${vueObj.searchByUtility ?? ''}&userDate=${userDate}`;
            await DataService.GetWorkCodeMappingList(url).then(function (response) {
                 debugger
                if (response.data != "" && response.data != null) {
                    if (response.data.result.length > 0) {
                        vueObj.RateScheduledeListing = response.data.result;

                        vueObj.TotalRecords = response.data.result[0].TOTAL_RECORDS;
                        vueObj.TotalPages = Math.ceil(vueObj.TotalRecords / vueObj.pageSize);
                        vueObj.CurrentPage = vueObj.pageNum;
                        vueObj.noRecord = false;
                    } else {
                        vueObj.noRecord = true;
                        vueObj.TotalRecords = 0
                        vueObj.RateScheduledeListing = [];
                    }
                }
                else {
                    vueObj.noRecord = true;
                    vueObj.TotalRecords = 0
                    vueObj.RateScheduledeListing = [];
                }
            })
        },
        getUserDate() {
    const d = new Date();
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`; // YYYY-MM-DD
},
        actionButtonClick(callbackfunction, item) {
            var vm = this;
            switch (callbackfunction) {
                case 'Edit':
                    vm.Edit(item);
                    break;
                      case 'EditDate':
                    vm.EditDate(item);
                    break;
                

            }
        },
         renderActions(row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Edit':
                        action.isVisible = true;
                        break;
                    case 'EditDate':
                        action.isVisible = true;
                        break;
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
      
